const Formatter={price:function(e){if(null==e)return"0";const t=Number(e);return isNaN(t)?"0":t.toLocaleString("ko-KR")},date:function(e,t="-"){if(!e)return"-";let r=String(e).replace(/[^0-9]/g,"");return 8===r.length?r.replace(/(\d{4})(\d{2})(\d{2})/,`$1${t}$2${t}$3`):6===r.length?r.replace(/(\d{4})(\d{2})/,`$1${t}$2`):e},phone:function(e){if(!e)return"-";let t=String(e).replace(/[^0-9]/g,"");return 11===t.length?t.replace(/(\d{3})(\d{4})(\d{4})/,"$1-$2-$3"):10===t.length?t.startsWith("02")?t.replace(/(\d{2})(\d{4})(\d{4})/,"$1-$2-$3"):t.replace(/(\d{3})(\d{3})(\d{4})/,"$1-$2-$3"):9===t.length&&t.startsWith("02")?t.replace(/(\d{2})(\d{3})(\d{4})/,"$1-$2-$3"):e},getByteLength:function(e){if(!e)return 0;let t=0;for(let r=0;r<e.length;r++){t+=e.charCodeAt(r)>127?3:1}return t}};